  name: "Festa-Standardization",
  inheritAttrs: false,//부모로부터 전달 받은 Attribute가 자식의 Attribute로 설정되지 않음
  data() {
    return {
      scrollActive: false,
    }
  },
  methods: {
    scrollEvent(){
      const scrollTop = window.pageYOffset || document.documentElement.scrollTop
      const currentScrollTop = document.querySelector(".first").offsetTop;
      if(scrollTop > currentScrollTop){
        this.scrollActive = true
      } else{
        this.scrollActive = false
      }
    },
    goBack(){
      this.$router.go(-1);
    }
  },
  mounted(){
    document.addEventListener('scroll', this.scrollEvent);
  },
  unmounted() {
    document.removeEventListener('scroll', this.scrollEvent);
  },
}
</script>

